select

from t_func_history
where func_type = #{funcType,jdbcType=VARCHAR}
  and (summary like #{keyword,jdbcType=VARCHAR}
    or input_text like #{keyword,jdbcType=VARCHAR}
    or output_text like #{keyword,jdbcType=VARCHAR}
    or extra_data like #{keyword,jdbcType=VARCHAR})
order by create_time desc, id desc

select count(*)
from t_func_history
where func_type = #{funcType,jdbcType=VARCHAR}
